<script>let name="JDesk",status="Connecting…",nonce,nextId=0;document.addEventListener("jdesk-message",({detail})=>{const m=JSON.parse(detail);if(m.kind==="nonce"){nonce=m.nonce;window.__jdesk.post(JSON.stringify({v:1,kind:"hello",client:"svelte",clientVersion:"0.1.0",nonce}));}else if(m.kind==="helloAck")status="Connected";else if(m.kind==="result")status=m.ok?m.value.message:m.error.message;});function greet(){window.__jdesk.post(JSON.stringify({v:1,kind:"invoke",id:`request-${++nextId}`,command:"greeting.greet",nonce,payload:{name}}));}</script><main><h1>@PROJECT_NAME@</h1><form onsubmit={(e)=>{e.preventDefault();greet();}}><input bind:value={name}><button>Greet</button></form><p>{status}</p></main>
